function showResult(n){resultBlock.textContent=JSON.stringify(n,null,2)}function showResultInsertStudent(n){document.getElementById("result").innerHTML=n}async function loadStudents(){const n=await fetch("https://localhost:7142/api/students");if(!n.ok){showResult("Ошибка: "+n.status);return}const t=await n.json();showResult(t)}async function loadCourses(){const n=await fetch("https://localhost:7142/api/courses");if(!n.ok){showResult("Ошибка: "+n.status);return}const t=await n.json();showResult(t)}async function loadEnrollments(){const n=await fetch("https://localhost:7142/api/enrollments");if(!n.ok){showResult("Ошибка: "+n.status);return}const t=await n.json();showResult(t)}async function addStudent(){const i=document.getElementById("courseUid").value,r=document.getElementById("studentName").value,u=document.getElementById("studentSurname").value,f=parseInt(document.getElementById("studentAge").value),e=parseInt(document.getElementById("studentGroup").value),n={courseUid:i,name:r,surname:u,age:f,group:e},t=await fetch("https://localhost:7142/api/students",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(n)});if(t.status===201||t.status===200)showResultInsertStudent("Студент успешно добавлен на курс!<br>courseUid: "+n.courseUid+"<br>Имя: "+n.name+"<br>Фамилия: "+n.surname+"<br>Группа: "+n.group);else{const n=await t.text();showResult("Ошибка при добавлении: "+t.status+"\n"+n)}}const resultBlock=document.getElementById("result");document.getElementById("btnStudents").addEventListener("click",loadStudents);document.getElementById("btnCourses").addEventListener("click",loadCourses);document.getElementById("btnEnrollments").addEventListener("click",loadEnrollments);document.getElementById("btnAddStudent").addEventListener("click",addStudent);